import React from 'react';
import { View, Text, Button } from 'react-native';
import * as Purchases from '@react-native-purchases/purchases';

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      products: [],
      selectedProduct: null,
    };
  }

  componentDidMount() {
    this.fetchProducts();
  }

  async fetchProducts() {
    try {
      const { products } = await Purchases.getProducts(['product_id_1', 'product_id_2']);
      this.setState({ products });
    } catch (error) {
      console.error('Error fetching products:', error);
    }
  }

  handlePurchase = async () => {
    if (!this.state.selectedProduct) return;

    try {
      const { transaction, customerInfo } = await Purchases.purchaseProduct(this.state.selectedProduct.identifier);
      console.log('Transaction:', transaction);
      console.log('Customer Info:', customerInfo);
    } catch (error) {
      console.error('Error purchasing product:', error);
    }
  };

  render() {
    return (
      <View>
        {this.state.products.map(product => (
          <Button
            key={product.identifier}
            title={product.title}
            onPress={() => this.setState({ selectedProduct: product })}
          />
        ))}
        {this.state.selectedProduct && (
          <Button title="Purchase" onPress={this.handlePurchase} />
        )}
      </View>
    );
  }
}

export default PaymentModule;